// Import necessary modules
import * as fetch from 'node-fetch';
import { SendGrid } from '@sendgrid/mail';
import Stripe from 'stripe';

// Set up your API keys
const sendgridAPIKey = process.env.SENDGRID_API_KEY;
const stripeSecretKey = process.env.STRIPE_SECRET_KEY;

// Initialize SendGrid and Stripe clients
SendGrid.setApiKey(sendgridAPIKey);
const sgMail = SendGrid.api;
const stripe = new Stripe(stripeSecretKey, { apiVersion: '2020-08-27' });

// Your worker route handling function
export async function handleRequest(request) {
  const body = await request.text();
  const data = JSON.parse(body);

  // Simulate some user action here to trigger sending an email and processing a payment

  try {
    // Send email with SendGrid
    const message = {
      to: 'user@example.com', // Replace with recipient's email address
      from: 'sender@example.com', // Replace with sender's email address
      subject: 'Test Email',
      text: 'This is a test email.',
    };
    sgMail.send(message);

    // Process payment with Stripe
    const charge = await stripe.charges.create({
      amount: 1000, // Amount in cents
      currency: 'usd',
      source: data.token, // Token from the customer's card
    });

  } catch (error) {
    console.error(error);
    // Handle errors appropriately for production
  }

  return new Response('Email sent and payment processed', { status: 200 });
}